"import shutil
import subprocess
import os

print("=== CHECKING CLI TOOLS ===")
for cmd in ["rclone", "gdrive", "onedrive", "git", "gh"]:
    path = shutil.which(cmd)
    print(f"{cmd}: {path}")

print("\n=== CHECKING RCLONE CONFIG ===")
rclone_config = os.path.expanduser("~/.config/rclone/rclone.conf")
print(f"Rclone config path exists: {os.path.exists(rclone_config)}")
if os.path.exists(rclone_config):
    try:
        with open(rclone_config, 'r') as f:
            for line in f:
                if line.startswith("["):
                    print(f"Remote: {line.strip()}")
    except Exception as e:
        print(f"Error reading rclone config: {e}")

print("\n=== CHECKING MOUNTED FILESYSTEMS ===")
try:
    res = subprocess.run(["mount"], capture_output=True, text=True)
    for line in res.stdout.splitlines():
        if "onedrive" in line.lower() or "drive" in line.lower() or "google" in line.lower():
            print(line)
